+    fn categorical_from_codes_allows_missing_code() {
+        let categories = vec![Scalar::Utf8("low".into()), Scalar::Utf8("high".into())];
+        let s =
+            Series::from_categorical_codes("rating", vec![0, -1, 1], categories, false).unwrap();
